// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const configGet = await fetch(`/platform/automation/v1/executions/${execution_id}/tasks/create-flow-logs/result`);
  const configBody = await configGet.json();

  if (!configBody.FlowLogIds || configBody.FlowLogIds.length === 0) {
    console.log("VPC Flow Logs creation failed!");
    throw new Error("VPC Flow Logs creation failed!");
  }

  console.log("VPC Flow Logs enabled successfully");
  console.log("Flow Log ID: " + configBody.FlowLogIds[0]);

  return configBody;
}
